-- First, get the lesson IDs to delete
SELECT id FROM lessons WHERE (courseId = 4 AND `order` IN (8, 9)) OR (courseId = 6 AND `order` = 9);

-- Delete quiz questions for these lessons  
DELETE FROM quiz_questions WHERE lessonId IN (
  SELECT id FROM lessons WHERE (courseId = 4 AND `order` IN (8, 9)) OR (courseId = 6 AND `order` = 9)
);

-- Delete the lessons
DELETE FROM lessons WHERE (courseId = 4 AND `order` IN (8, 9)) OR (courseId = 6 AND `order` = 9);

-- Update course totals
UPDATE courses SET totalLessons = 7 WHERE id = 4;
UPDATE courses SET totalLessons = 8 WHERE id = 6;

